#pragma kernel BiomeCSMain

#include "Assets/ComputeShaders/noiseSimplex.cginc"

RWStructuredBuffer<int3> colors;


Texture2D<float> heightsTex;
SamplerState samplerLinear {
    Filter = MIN_MAG_MIP_LINEAR;
    AddressU = Clamp;
    AddressV = Clamp;
};

float biomeFrequency;

int textureresolution;
int terrainresolution;
float maxAmp;

float xOffset;
float yOffset;

int3 colorassign(int x, int y) {

    // Map texture pixel (x,y) into normalized UV coords for sampling heightsTex
    float invSize = 1.0f / max(1.0f, (float)(textureresolution - 1));
    // Map to terrain-space float coords (matching how heights were laid out)
    float sizing = (float)(terrainresolution - 1);
    float fx = x * sizing * invSize;
    float fy = y * sizing * invSize;

    // Normalized UV in [0,1] for hardware bilinear sampling
    float2 uv = float2(fx / (terrainresolution - 1), fy / (terrainresolution - 1));
    float heightSample = heightsTex.SampleLevel(samplerLinear, uv, 0).r;
    float height = heightSample / maxAmp;

    // Use continuous terrain coords for noise so texture varies smoothly
    float2 pos = float2(xOffset, yOffset) + float2(fx, fy) * biomeFrequency;
    // Combine height + noise for biome decision
    if (height < 0.2)
    {
        return int3(0, 128, 255); // Water
    }
    else if (height < 0.25)
    {
        return int3(194, 178, 128); // Beach
    }
    else if (height < 0.5)
    {
        return int3(34, 139, 34); // Dense vegetation
    }
    else if (height < 0.6)
    {
        return int3(107, 142, 35); // Grass
    }
    else
    {
        return int3(139, 137, 137); // Rock/snow
    }

}


[numthreads(16,16,1)]
void BiomeCSMain (uint3 id : SV_DispatchThreadID)
{

    uint x = id.x;
    uint y = id.y;
    if (x >= textureresolution || y >= textureresolution) return;

    uint idx = x + y * textureresolution;

    colors[idx] = colorassign(id.x, id.y);
}

